CREATE VIEW "public"."current_price_bars" AS (select distinct on ("price_bars"."instrument_id", "price_bars"."provider_id", "price_bars"."timeframe", "price_bars"."open_time") "id", "instrument_id", "provider_id", "timeframe", "open_time", "close_time", "open", "high", "low", "close", "volume", "is_closed", "source_timestamp", "ingested_at", "revision", "quality_status", "created_at", "updated_at" from "price_bars" order by "price_bars"."instrument_id", "price_bars"."provider_id", "price_bars"."timeframe", "price_bars"."open_time", "price_bars"."revision" desc);